// Hilfsfunktion zur Bereinigung von Strings (entfernt \n und trimmt)
const clean = (val) => (typeof val === 'string' ? val.replace(/\n/g, '').trim() : val);

// Wir iterieren über die eingegangenen Items (Array-Struktur von n8n)
return items.map(item => {
    const input = item.json;

    // Transformation
    const output = {
        plantContext: {
            anlagenName: input.processDescription?.purpose || "",
            standort: `${input.location?.site || ""}, ${input.location?.building || ""}`,
            betriebsbedingungen: {
                temperatur: `${input.processDescription?.description.match(/(\d+-\d+°C)/)?.[0] || "80-100 °C"}`,
                druck: `${input.processDescription?.description.match(/(\d+-\d+(\.\d+)? bar)/)?.[0] || "1-1.2 bar"}`,
                medium: [
                    ...(input.feedstocks?.map(f => f.name) || []),
                    ...(input.products?.map(p => p.name) || [])
                ].join(", ")
            },
            sicherheitsklasse: "SIL-1", // Standardwert aus Input-Logik
            beschreibung: input.processDescription?.description || "",
            betriebsart: input.processDescription?.operatingMode || "",
            operator: input.generalInfo?.operator || "",
            department: input.generalInfo?.department || ""
        },
        stoffe: {
            feedstocks: input.feedstocks || [],
            products: input.products || [],
            // Hier trennen wir strikt: Nur chemische Nebenprodukte
            byproducts: (input.byproducts || []).filter(b => 
                !["kühlwasser", "eiswasser", "sole"].includes(b.name.toLowerCase())
            ),
            // Hier kommen alle Versorgungsmedien rein
            media: [
                ...(input.media || []),
                // Falls Kühlwasser fälschlich in byproducts landete, hierher schieben
                ...(input.byproducts || []).filter(b => 
                    ["kühlwasser", "eiswasser", "sole"].includes(b.name.toLowerCase())
                ).map(b => ({ ...b, category: "heating-cooling" }))
            ]
        },
        // Systeme 1:1 übernehmen und Werte bereinigen
        systems: (input.systems || []).map(sys => ({
            ...sys,
            designData: (sys.designData || []).map(d => ({
                ...d,
                value: clean(d.value) // Entfernt das \n bei 60°C
            }))
        })),
        generalInfo: input.generalInfo || {},
        planning: {
            intent: `FMEA-Analyse für ${input.processDescription?.purpose || "Anlage"}`,
            timing: new Date().toISOString(),
            team: "Automatisierte Analyse",
            tools: "AIAG-VDA FMEA-Methodik"
        },
        metadata: {
            workflowStarted: new Date().toISOString(),
            systemAnzahl: (input.systems || []).length,
            anlagenName: input.processDescription?.purpose || ""
        }
    };

    return { json: output };
});

