// --- 1. HILFSFUNKTION: INTELLIGENTE TYP-ERKENNUNG ---
function inferKomponententyp(name, type, parameters) {
  const combined = (name + ' ' + (type || '')).toUpperCase();

  if (combined.match(/SICHERHEIT|PSV|BSV|BERST|UEBERDRUCK|NOTAUS|ALARM/)) return 'sicherheit';
  if (combined.match(/STICKSTOFF|VAKUUM|NETZ|VERSORGUNG|MEDIEN|DRUCKLUFT/)) return 'prozess';
  if (combined.match(/DOSIER|MEMBRAN/)) return 'dosierung';
  if (combined.match(/PUMPE|VERDICHTER|TURBINE|GETRIEBE|LAGER|WELLE|KUPPLUNG|RUEHRWERK|RUEHRER/)) return 'mechanisch';
  if (combined.match(/HEIZ|KUEHL|WAERME|KONDENSATOR|MANTEL|DAMPF/)) return 'thermisch';
  if (combined.match(/REAKTOR|TANK|BEHAELTER|VORLAGE|KOLONNE|DESTILLATION|FILTER/)) return 'prozess';
  if (combined.match(/SENSOR|TRANSMITTER|MESSUMFORMER|SCHALTER|RELAIS|MOTOR|KABEL|TIC|PIC|LIC|FIC|TEMPERATUR|DRUCK|FUELLSTAND|DURCHFLUSS/)) return 'elektrisch';

  return 'sonstige';
}

