function getRPZStatus(rpz, limits) {
    const kritisch = limits.find(l => l.name === "limit_kritisch")?.wert || 300;
    const hoch = limits.find(l => l.name === "limit_hoch")?.wert || 200;
    const mittel = limits.find(l => l.name === "limit_mittel")?.wert || 100;

    if (rpz >= kritisch) return "kritisch";
    if (rpz >= hoch) return "hoch";
    if (rpz >= mittel) return "mittel";
    return "niedrig";
}

