    data.begruendung = `[AUTOMATISCHER OVERRIDE: ${appliedOverride}] ` + (data.begruendung || "");

    // Klasse neu bestimmen
    if (data.RPZ >= 300) data.risikoklasse = "Kritisch";
    else if (data.RPZ >= 200) data.risikoklasse = "Hoch";
