  valMittel = limits.find(l => l.name === 'limit_mittel')?.wert || 100;
  valHoch = limits.find(l => l.name === 'limit_hoch')?.wert || 200;
  valKritisch = limits.find(l => l.name === 'limit_kritisch')?.wert || 300;
}

// Hilfsfunktion zur Risikoklasse
function getRisikoStatus(rpz) {
  const v = Number(rpz);
  if (isNaN(v)) return "unbekannt";
  if (v >= valKritisch) return "kritisch";
  if (v >= valHoch) return "hoch";
  if (v >= valMittel) return "mittel";
  return "niedrig";
}

return originalData.map(item => {
  const data = { ...item.json };
  const fId = data.fehler_id;

  // Aufräumen: Unnötige Felder entfernen
  delete data.prozess_details;
  delete data.limit_kritisch; 

  const matchingMeasure = aiMeasures.find(ai => 
    ai.json.refId && fId && String(ai.json.refId).trim() === String(fId).trim()
  );

  let result = {
    ...data,
    "RPZ Status": getRisikoStatus(data.rpz), // Ursprünglicher Status
    massnahme_generiert: null,
    restrisiko: null
  };

  if (matchingMeasure) {
    const rpzNeu = matchingMeasure.json.rpz_neu;

    result.massnahme_generiert = {
      name: matchingMeasure.json.massnahme_name,
      kategorie: matchingMeasure.json.abe_kategorie,
      beschreibung: matchingMeasure.json.beschreibung
    };

    result.restrisiko = {
      S_neu: matchingMeasure.json.restrisiko_S,
      O_neu: matchingMeasure.json.restrisiko_O,
      D_neu: matchingMeasure.json.restrisiko_D,
      rpz_neu: rpzNeu,
      "RPZ Status neu": getRisikoStatus(rpzNeu), // Neuer Status
      begruendung: matchingMeasure.json.logik_check
    };

    result.risiko_delta = (Number(data.rpz) || 0) - (Number(rpzNeu) || 0);
  }

  return { json: result };
});

// ============================================================
// MERGE: FMEA-DETAILS + ANLAGENKONTEXT
// ============================================================

// 1. Zugriff auf die Daten der Structure Analysis Node
// Der Name in $(...) muss exakt dem Namen der Node entsprechen
const structureData = $('Structure Analysis').all();

// 2. Map erstellen für schnellen Zugriff über die ID (KOMP-XXX)
const structureMap = {};
structureData.forEach(item => {
  structureMap[item.json.id] = item.json;
});

const finalFMEA = [];

// 3. Über die aktuellen FMEA-Items (Input dieser Node) iterieren
for (const item of items) {
  const fmeaEntry = item.json;
  const kompId = fmeaEntry.komponenten_id;

  // Die passenden Anlagendaten finden
  const anlage = structureMap[kompId] || {};

  // 4. Daten zusammenführen
  finalFMEA.push({
    // --- FMEA Kern-Daten ---
    komponenten_id: kompId,
    komponente: fmeaEntry.komponente,
    fehler_id: fmeaEntry.fehler_id,
    fehlermodus: fmeaEntry.fehlermodus,
    fehlerart: fmeaEntry.fehlerart,
    ursachen: fmeaEntry.fehlerursachen,
    folgen: fmeaEntry.fehlerfolgen,

    // --- Risikobewertung & RPZ ---
    risiko: fmeaEntry.risikobewertung,
    rpz: (fmeaEntry.risikobewertung?.S || 0) * (fmeaEntry.risikobewertung?.O || 0) * (fmeaEntry.risikobewertung?.D || 0),

    // --- Technischer Kontext aus Structure Analysis ---
    system: anlage.systemName || "k.A.",
    komponenten_typ: anlage.typ || "k.A.",
    prozess_details: {
        druck_temp: anlage.lean_context?.process_conditions || {},
        medien: anlage.lean_context?.active_substances || [],
        verfuegbare_sensorik: anlage.lean_context?.available_sensors || [],
        sicherheitseinrichtungen: anlage.lean_context?.safety_features || []
    }
  });
}

// 5. Ergebnis ausgeben
return finalFMEA.map(f => ({ json: f }));

// ============================================================
// MERGE: FUNKTIONEN + STRUKTURDATEN
// ============================================================

// 1. Hol dir alle Komponenten aus der "Structure Analysis" Node
// Ersetze 'Structure Analysis' exakt durch den Namen deiner Node
const structureData = $( 'Structure Analysis' ).all();

// 2. Erstelle eine Map für schnellen Zugriff via ID
const structureMap = {};
structureData.forEach(item => {
  structureMap[item.json.id] = item.json;
});

const mergedResults = [];

// 3. Iteriere über die Funktionen (Input dieser Node)
for (const item of items) {
  const func = item.json;
  const kompId = func.komponenten_id;

  // Suche die passenden Strukturdaten
  const detail = structureMap[kompId] || {};

  // 4. Kombiniere die Daten
  mergedResults.push({
    // Basis-Infos aus der Funktionsanalyse
    komponenten_id: kompId,
    komponente: func.komponente,
    funktion_id: func.funktion_id,
    funktion_typ: func.funktion_typ,
    funktion_beschreibung: func.funktion_beschreibung,
    anforderungen: func.anforderungen,

    // Ergänzte Infos aus der Struktur-Analyse
    systemName: detail.systemName || "k.A.",
    komponenten_typ: detail.typ || func.komponenten_typ,
    beschreibung_technisch: detail.beschreibung || "",
    parameters: detail.parameters || {},
    lean_context: detail.lean_context || {}
  });
}

// 5. Rückgabe der angereicherten Funktions-Items
return mergedResults.map(r => ({ json: r }));

// 1. Extrahiere den Text aus dem LLM-Input
let rawText = $json.text;

// 2. Säuberung von Markdown-Code-Blocks (Entfernt ```json und ```)
if (rawText.includes('```json')) {
    rawText = rawText.replace(/```json/g, '').replace(/```/g, '');
} else if (rawText.includes('```')) {
    rawText = rawText.replace(/```/g, '');
}

try {
    // 3. String in ein JSON-Objekt umwandeln
    const parsedData = JSON.parse(rawText.trim());

    // 4. Rückgabe der bereinigten Daten
    // Wir geben alle Felder der KI-Antwort direkt auf der obersten Ebene zurück
    return {
        refId: parsedData.refId,
        massnahme_name: parsedData.massnahme_name,
        abe_kategorie: parsedData.abe_kategorie,
        beschreibung: parsedData.beschreibung,
        restrisiko_S: parsedData.restrisiko.S,
        restrisiko_O: parsedData.restrisiko.O,
        restrisiko_D: parsedData.restrisiko.D,
        // Berechnung der neuen RPZ zur Sicherheit
        rpz_neu: parsedData.restrisiko.S * parsedData.restrisiko.O * parsedData.restrisiko.D,
        logik_check: parsedData.logik_check
    };

} catch (error) {
    // Falls das LLM kein valides JSON liefert, geben wir eine Fehlermeldung aus
    return {
        error: "JSON Parsing fehlgeschlagen",
        raw_output: rawText,
        error_details: error.message
    };
}

